import ReactDOM from 'react-dom/client';
import './style.css'


const root = ReactDOM.createRoot(document.getElementById('root'));

function Navbar(){
  return(
    <nav>
    <h1>Perfumy</h1>
    <ul>
      <li> Home | </li>
      <li>Products | </li>
      <li>About | </li>
      <li>Contact | </li>
    </ul>
    </nav>
)

}

function Searchbar(){
  return(
    <div class="searchbar">
      <input type="text" placeholder="Search"></input>
    </div>

  )
}

function Products(){
  return(
     <div class="products">
       <div class="box">
        <img src="./images/one.jpg"></img>
                        <p>Fogg Wood Extreme, Eau De Parfum, Long-lasting Perfume, 100ml</p>
       </div>
     </div>
  )
}





root.render(
<div>
  <Navbar></Navbar>
  <Searchbar></Searchbar>
</div>);
